### 3) Evaluation Pipeline Helper
```rust
/// Evaluate an embedder against the ground truth corpus
/// Returns QualityMetrics averaged across all queries
pub fn evaluate_quality(
    embedder: &dyn Embedder,
    corpus: &Corpus,
    top_k: usize,
) -> Result<QualityMetrics> {
    let mut ndcg_scores = Vec::new();
    let mut mrr_scores = Vec::new();
    let mut map_scores = Vec::new();
    let mut recall_scores = Vec::new();
    let mut precision_scores = Vec::new();

    // Embed all corpus documents
    let doc_texts: Vec<&str> = corpus.documents.iter().map(|d| d.text.as_str()).collect();
    let doc_embeddings = embedder.embed_batch(&doc_texts)?;

    for query in &corpus.queries {
        let query_emb = embedder.embed_batch(&[query.text.as_str()])?;
        let query_vec = &query_emb[0];

        // Compute cosine similarities (embeddings are normalized, so dot product)
        let mut scores: Vec<(usize, f64)> = doc_embeddings.iter()
            .enumerate()
            .map(|(i, doc_emb)| {
                let sim = dot_product(query_vec, doc_emb);
                (i, sim as f64)
            })
            .collect();
        scores.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());

        // Map to relevance judgments
        let ranked_rels: Vec<f64> = scores.iter()
            .take(top_k.max(100))
            .map(|(idx, _)| {
                let doc_id = &corpus.documents[*idx].id;
                query.relevants.get(doc_id).copied().unwrap_or(0.0)
            })
            .collect();

        ndcg_scores.push(ndcg_at_k(&ranked_rels, 10));
        mrr_scores.push(mrr(&ranked_rels, 1.0));
        map_scores.push(map_at_k(&ranked_rels, 10, 1.0));
        recall_scores.push(recall_at_k(&ranked_rels, 100, 1.0));
        precision_scores.push(precision_at_k(&ranked_rels, 10, 1.0));
    }

    Ok(QualityMetrics {
        ndcg_at_10: mean(&ndcg_scores),
        mrr_at_10: mean(&mrr_scores),
        map_at_10: mean(&map_scores),
        recall_at_100: mean(&recall_scores),
        precision_at_10: mean(&precision_scores),
    })
}
