pub struct ReplPrompt {
    theme: Theme,
    mode: SearchMode,
    history_position: Option<usize>,
}

impl Default for ReplPrompt {
    fn default() -> Self {
        Self {
            theme: Theme::default(),
            mode: SearchMode::default(),
            history_position: None,
        }
    }
}

impl ReplPrompt {
    pub fn new(theme: &Theme) -> Self {
        Self {
            theme: theme.clone(),
            mode: SearchMode::default(),
            history_position: None,
        }
    }

    pub fn with_mode(mut self, mode: SearchMode) -> Self {
        self.mode = mode;
        self
    }

    pub fn render(&self, output: &Output, mode: SearchMode) -> String {
        if !output.is_styled() {
            return format!("xf ({})> ", mode);
        }

        let mode_color = match mode {
            SearchMode::Hybrid => self.theme.primary,
            SearchMode::Lexical => self.theme.secondary,
            SearchMode::Semantic => self.theme.info,
        };

        format!(
            "[{}]xf[/] ([{} bold]{}[/]) [{}]❯[/] ",
            self.theme.primary,
            mode_color,
            mode,
            self.theme.success
        )
    }
}
