+    /// Size of the original archive (ZIP or extracted)
+    pub archive_bytes: u64,
+    /// Size of the search index directory
+    pub index_bytes: u64,
+    /// Size of the SQLite database
+    pub database_bytes: u64,
+    /// Path to the archive
+    pub archive_path: Option<PathBuf>,
+}
+
+impl StorageInfo {
